1	<?php
2	
3	namespace App\Policies;
4	
5	use App\Models\Document;
6	use App\Models\User;
7	
8	class DocumentPolicy
9	{
10	    /**
11	     * Admin bypasses all checks.
12	     */
13	    public function before(User $user, string $ability): ?bool
14	    {
15	        if ($user->hasRole('admin')) {
16	            return true;
17	        }
18	
19	        return null;
20	    }
21	
22	    /**
23	     * Any user with 'view documents' permission can list documents.
24	     */
25	    public function viewAny(User $user): bool
26	    {
27	        return $user->can('view documents');
28	    }
29	
30	    /**
31	     * A user can view a document if they have the permission and the document
32	     * is in their department — or they have cross-department/system-wide scope.
33	     */
34	    public function view(User $user, Document $document): bool
35	    {
36	        return $user->can('view documents')
37	            && ($this->inSameDepartment($user, $document) || $this->hasCrossScope($user));
38	    }
39	
40	    /**
41	     * Any user with 'create documents' permission can create a document.
42	     */
43	    public function create(User $user): bool
44	    {
45	        return $user->can('create documents');
46	    }
47	
48	    /**
49	     * A user can update a document if:
50	     *   - They have the update permission
51	     *   - The document is in their department or they have cross-department scope
52	     *   - The document is not archived
53	     */
54	    public function update(User $user, Document $document): bool
55	    {
56	        return $user->can('update documents')
57	            && ($this->inSameDepartment($user, $document) || $this->hasCrossScope($user))
58	            && !$document->is_archived;
59	    }
60	
61	    /**
62	     * A user can archive a document if they have the permission and it isn't already archived.
63	     */
64	    public function archive(User $user, Document $document): bool
65	    {
66	        return $user->can('archive documents') && !$document->is_archived;
67	    }
68	
69	    // -------------------------------------------------------------------------
70	    // Shared helpers
71	    // -------------------------------------------------------------------------
72	
73	    protected function inSameDepartment(User $user, Document $document): bool
74	    {
75	        return $user->department_id !== null
76	            && $user->department_id === $document->department_id;
77	    }
78	
79	    protected function hasCrossScope(User $user): bool
80	    {
81	        return $user->hasRole(['admin', 'manager', 'auditor']);
82	    }
83	}
