3	namespace App\Policies;
4	
5	use App\Models\SalesDocument;
6	use App\Models\User;
7	
8	class SalesDocumentPolicy
9	{
10	    /**
11	     * Admin bypasses all checks.
12	     */
13	    public function before(User $user, string $ability): ?bool
14	    {
15	        if ($user->hasRole('admin')) {
16	            return true;
17	        }
18	
19	        return null;
20	    }
21	
22	    public function viewAny(User $user): bool
23	    {
24	        return $user->can('view sales') || $user->can('manage sales');
25	    }
26	
27	    /**
28	     * Department-scoped: user can only view documents in their department unless
29	     * they have manager or auditor role (cross-department access).
30	     */
31	    public function view(User $user, SalesDocument $document): bool
32	    {
33	        $hasPermission = $user->can('view sales') || $user->can('manage sales');
34	
35	        return $hasPermission
36	            && ($this->inSameDepartment($user, $document) || $this->hasCrossScope($user));
37	    }
38	
39	    public function create(User $user): bool
40	    {
41	        return $user->can('create sales');
42	    }
43	
44	    /**
45	     * Can update only if: has manage permission and document is still editable.
46	     */
47	    public function update(User $user, SalesDocument $document): bool
48	    {
49	        return $user->can('manage sales') && $document->status->isEditable();
50	    }
51	
52	    public function void(User $user, SalesDocument $document): bool
53	    {
54	        return $user->can('void sales');
55	    }
56	
57	    // -------------------------------------------------------------------------
58	    // Shared helpers
59	    // -------------------------------------------------------------------------
60	
61	    protected function inSameDepartment(User $user, SalesDocument $document): bool
62	    {
63	        return $user->department_id !== null
64	            && $user->department_id === $document->department_id;
65	    }
66	
67	    protected function hasCrossScope(User $user): bool
68	    {
69	        return $user->hasRole(['manager', 'auditor']);
70	    }
71	}
