3	namespace App\Http\Controllers\Api;
4	
5	use App\Application\Sales\SalesDocumentService;
6	use App\Http\Controllers\Controller;
7	use App\Http\Requests\Sales\StoreSalesDocumentRequest;
8	use App\Http\Requests\Sales\UpdateSalesDocumentRequest;
9	use App\Http\Requests\Sales\VoidSalesDocumentRequest;
10	use App\Models\SalesDocument;
11	use Illuminate\Http\JsonResponse;
12	use Illuminate\Http\Request;
13	use Illuminate\Http\Response;
14	
15	class SalesDocumentController extends Controller
16	{
17	    public function __construct(
18	        private readonly SalesDocumentService $service,
19	    ) {}
20	
21	    /**
22	     * GET /api/v1/sales
23	     */
24	    public function index(Request $request): JsonResponse
25	    {
26	        $this->authorize('viewAny', SalesDocument::class);
27	
28	        $user  = $request->user();
29	        $query = SalesDocument::query()->with(['department', 'createdBy']);
30	
31	        // Department scope: non-elevated users see only their department
32	        if (!$user->hasRole(['admin', 'manager', 'auditor'])) {
33	            $query->where('department_id', $user->department_id);
34	        }
35	
36	        if ($request->has('filter.status')) {
37	            $query->where('status', $request->input('filter.status'));
38	        }
39	
40	        if ($request->has('filter.department_id') && $user->hasRole(['admin', 'manager'])) {
41	            $query->where('department_id', $request->input('filter.department_id'));
42	        }
43	
44	        $perPage   = min((int) $request->input('per_page', 25), 100);
45	        $paginated = $query->orderBy('created_at', 'desc')->paginate($perPage);
46	
47	        return response()->json([
48	            'data' => $paginated->map(fn(SalesDocument $d) => $this->docShape($d)),
49	            'meta' => [
50	                'pagination' => [
51	                    'current_page' => $paginated->currentPage(),
52	                    'per_page'     => $paginated->perPage(),
53	                    'total'        => $paginated->total(),
54	                    'last_page'    => $paginated->lastPage(),
55	                ],
56	            ],
57	        ]);
58	    }
59	
60	    /**
61	     * POST /api/v1/sales
62	     */
63	    public function store(StoreSalesDocumentRequest $request): JsonResponse
64	    {
65	        $doc = $this->service->create(
66	            $request->user(),
67	            $request->validated(),
68	            $request->ip()
69	        );
70	
71	        return response()->json(['data' => $this->docShape($doc)], 201);
72	    }
73	
74	    /**
75	     * GET /api/v1/sales/{document}
76	     */
77	    public function show(Request $request, SalesDocument $document): JsonResponse
78	    {
79	        $this->authorize('view', $document);
80	
81	        $document->load(['department', 'createdBy', 'lineItems', 'returns']);
82	
83	        return response()->json(['data' => $this->docShape($document, withLineItems: true, withReturns: true)]);
84	    }
85	
86	    /**
87	     * PUT /api/v1/sales/{document}
88	     */
89	    public function update(UpdateSalesDocumentRequest $request, SalesDocument $document): JsonResponse
90	    {
91	        $this->authorize('update', $document);
92	
93	        $doc = $this->service->update(
94	            $request->user(),
95	            $document,
96	            $request->validated(),
97	            $request->ip()
98	        );
99	
100	        return response()->json(['data' => $this->docShape($doc, withLineItems: true)]);
101	    }
102	
103	    /**
104	     * POST /api/v1/sales/{document}/submit
105	     */
106	    public function submit(Request $request, SalesDocument $document): JsonResponse
107	    {
108	        $this->authorize('update', $document);
109	
110	        $doc = $this->service->submit(
111	            $request->user(),
112	            $document,
113	            $request->ip()
114	        );
115	
116	        return response()->json(['data' => $this->docShape($doc)]);
117	    }
118	
119	    /**
120	     * POST /api/v1/sales/{document}/complete
121	     */
122	    public function complete(Request $request, SalesDocument $document): JsonResponse
123	    {
124	        if (!$request->user()->can('manage sales')) {
125	            abort(403, 'You are not authorized to complete sales documents.');
126	        }
127	
128	        $document->load('lineItems');
129	
130	        $doc = $this->service->complete(
131	            $request->user(),
132	            $document,
133	            $request->ip()
134	        );
135	
136	        return response()->json(['data' => $this->docShape($doc)]);
137	    }
138	
139	    /**
140	     * POST /api/v1/sales/{document}/void
141	     */
142	    public function void(VoidSalesDocumentRequest $request, SalesDocument $document): JsonResponse
143	    {
144	        $this->authorize('void', $document);
145	
146	        $doc = $this->service->void(
147	            $request->user(),
148	            $document,
149	            $request->validated('reason'),
150	            $request->ip()
151	        );
152	
153	        return response()->json(['data' => $this->docShape($doc)]);
154	    }
155	
156	    /**
157	     * POST /api/v1/sales/{document}/link-outbound
158	     */
159	    public function linkOutbound(Request $request, SalesDocument $document): JsonResponse
160	    {
161	        if (!$request->user()->can('manage sales')) {
162	            abort(403, 'You are not authorized to link outbound on this document.');
163	        }
164	
165	        $doc = $this->service->linkOutbound(
166	            $request->user(),
167	            $document,
168	            $request->ip()
169	        );
170	
171	        return response()->json(['data' => $this->docShape($doc)]);
172	    }
173	
174	    // -------------------------------------------------------------------------
175	    // Private helpers
176	    // -------------------------------------------------------------------------
177	
178	    private function docShape(SalesDocument $doc, bool $withLineItems = false, bool $withReturns = false): array
179	    {
180	        $shape = [
181	            'id'                  => $doc->id,
182	            'document_number'     => $doc->document_number,
183	            'site_code'           => $doc->site_code,
184	            'status'              => $doc->status instanceof \BackedEnum ? $doc->status->value : $doc->status,
185	            'department_id'       => $doc->department_id,
186	            'created_by'          => $doc->created_by,
187	            'reviewed_by'         => $doc->reviewed_by,
188	            'total_amount'        => $doc->total_amount,
189	            'notes'               => $doc->notes,
190	            'completed_at'        => $doc->completed_at?->toIso8601String(),
191	            'voided_at'           => $doc->voided_at?->toIso8601String(),
192	            'voided_reason'       => $doc->voided_reason,
193	            'outbound_linked_at'  => $doc->outbound_linked_at?->toIso8601String(),
194	            'created_at'          => $doc->created_at?->toIso8601String(),
195	            'updated_at'          => $doc->updated_at?->toIso8601String(),
196	        ];
197	
198	        if ($withLineItems && $doc->relationLoaded('lineItems')) {
199	            $shape['line_items'] = $doc->lineItems->map(fn($item) => [
200	                'id'           => $item->id,
201	                'product_code' => $item->product_code,
202	                'description'  => $item->description,
203	                'quantity'     => $item->quantity,
204	                'unit_price'   => $item->unit_price,
205	                'line_total'   => $item->line_total,
206	            ])->values();
207	        }
208	
209	        if ($withReturns && $doc->relationLoaded('returns')) {
210	            $shape['returns'] = $doc->returns->map(fn($r) => [
211	                'id'                     => $r->id,
212	                'return_document_number' => $r->return_document_number,
213	                'status'                 => $r->status,
214	                'reason_code'            => $r->reason_code instanceof \BackedEnum ? $r->reason_code->value : $r->reason_code,
215	                'return_amount'          => (float) $r->restock_fee_amount + (float) $r->refund_amount,
216	                'restock_fee_amount'     => $r->restock_fee_amount,
217	                'refund_amount'          => $r->refund_amount,
218	                'created_at'             => $r->created_at?->toIso8601String(),
219	            ])->values();
220	        }
221	
222	        return $shape;
223	    }
224	}
