62	
63	    /**
64	     * PUT /api/v1/returns/{return}
65	     */
66	    public function update(Request $request, ReturnRecord $return): JsonResponse
67	    {
68	        if (!$request->user()->can('manage sales')) {
69	            abort(403, 'You are not authorized to update this return.');
70	        }
71	
72	        $validated = $request->validate([
73	            'reason_detail' => ['nullable', 'string', 'max:2000'],
