105	        $shape = [
106	            'id'                     => $return->id,
107	            'sales_document_id'      => $return->sales_document_id,
108	            'return_document_number' => $return->return_document_number,
109	            'reason_code'            => $return->reason_code instanceof \BackedEnum
110	                                            ? $return->reason_code->value
111	                                            : $return->reason_code,
112	            'reason_detail'          => $return->reason_detail,
113	            'is_defective'           => $return->is_defective,
114	            'restock_fee_percent'    => $return->restock_fee_percent,
115	            'restock_fee_amount'     => $return->restock_fee_amount,
116	            'refund_amount'          => $return->refund_amount,
117	            'status'                 => $return->status,
118	            'completed_at'           => $return->completed_at?->toIso8601String(),
119	            'created_by'             => $return->created_by,
120	            'created_at'             => $return->created_at?->toIso8601String(),
121	            'updated_at'             => $return->updated_at?->toIso8601String(),
122	        ];
123	
124	        if ($withDoc && $return->relationLoaded('salesDocument')) {
125	            $shape['sales_document'] = [
126	                'id'              => $return->salesDocument->id,
127	                'document_number' => $return->salesDocument->document_number,
128	                'site_code'       => $return->salesDocument->site_code,
129	            ];
130	        }
131	
132	        return $shape;
133	    }
134	}
