3	namespace App\Policies;
4	
5	use App\Models\Attachment;
6	use App\Models\User;
7	
8	class AttachmentPolicy
9	{
10	    /**
11	     * Admin bypasses all checks.
12	     */
13	    public function before(User $user, string $ability): ?bool
14	    {
15	        if ($user->hasRole('admin')) {
16	            return true;
17	        }
18	
19	        return null;
20	    }
21	
22	    /**
23	     * A user can list attachments on a record if they have the download permission.
24	     */
25	    public function viewAny(User $user): bool
26	    {
27	        return $user->can('download attachments');
28	    }
29	
30	    /**
31	     * A user can download/view an attachment if they have the download permission
32	     * and the attachment belongs to their department (admin and auditor are exempt).
33	     */
34	    public function view(User $user, Attachment $attachment): bool
35	    {
36	        if ($user->hasRole(['admin', 'auditor'])) {
37	            return $user->can('download attachments');
38	        }
39	
40	        return $user->can('download attachments')
41	            && $user->department_id !== null
42	            && $user->department_id === $attachment->department_id;
43	    }
44	
45	    /**
46	     * A user can upload a new attachment if they have the upload permission.
47	     */
48	    public function create(User $user): bool
49	    {
50	        return $user->can('upload attachments');
51	    }
52	
53	    /**
54	     * A user can revoke (soft-delete) an attachment if they have the revoke permission.
55	     */
56	    public function delete(User $user, Attachment $attachment): bool
57	    {
58	        return $user->can('revoke attachments');
59	    }
60	}
