1	<?php
2	
3	namespace App\Http\Controllers\Api;
4	
5	use App\Application\Attachment\AttachmentService;
6	use App\Http\Controllers\Controller;
7	use App\Http\Requests\Attachment\StoreAttachmentRequest;
8	use App\Models\Attachment;
9	use App\Models\Document;
10	use App\Models\ReturnRecord;
11	use App\Models\SalesDocument;
12	use Illuminate\Http\JsonResponse;
13	use Illuminate\Http\Request;
14	use Illuminate\Http\Response;
15	
16	class AttachmentController extends Controller
17	{
18	    /**
19	     * Map of URL-friendly type slugs to fully-qualified model class names.
20	     * Used to resolve the polymorphic record_type from the route parameter.
21	     */
22	    private const MORPH_MAP = [
23	        'document'       => Document::class,
24	        'sales_document' => SalesDocument::class,
25	        'return'         => ReturnRecord::class,
26	    ];
27	
28	    public function __construct(
29	        private readonly AttachmentService $service,
30	    ) {}
31	
32	    /**
33	     * GET /api/v1/records/{type}/{id}/attachments
34	     *
35	     * List active attachments for a business record.
36	     *
37	     * Authorization is delegated to the parent record's own policy so that
38	     * department isolation and access_control_scope rules are respected. A user
39	     * who cannot view the parent record cannot list its attachments.
40	     */
41	    public function index(Request $request, string $type, string $id): JsonResponse
42	    {
43	        $recordType = $this->resolveRecordType($type);
44	
45	        // Load the parent record and authorize via its own policy (enforces department scope)
46	        $record = $recordType::findOrFail($id);
47	        $this->authorize('view', $record);
48	
49	        $attachments = Attachment::where('record_type', $recordType)
50	            ->where('record_id', $id)
51	            ->whereNull('deleted_at')
52	            ->orderBy('created_at', 'desc')
53	            ->get();
54	
55	        return response()->json([
56	            'data' => $attachments->map(fn(Attachment $a) => $this->attachmentShape($a)),
57	        ]);
58	    }
59	
60	    /**
61	     * POST /api/v1/records/{type}/{id}/attachments
62	     *
63	     * Upload a new attachment to a business record.
64	     * Authorization enforced in StoreAttachmentRequest::authorize().
65	     */
66	    public function store(StoreAttachmentRequest $request, string $type, string $id): JsonResponse
67	    {
68	        $recordType = $this->resolveRecordType($type);
69	
70	        $attachment = $this->service->upload(
71	            $request->user(),
72	            $recordType,
73	            $id,
74	            $request->file('file'),
75	            $request->has('validity_days') ? (int) $request->input('validity_days') : null,
76	            $request->ip()
77	        );
78	
79	        return response()->json(['data' => $this->attachmentShape($attachment)], 201);
80	    }
81	
82	    /**
83	     * GET /api/v1/attachments/{attachment}
84	     *
85	     * Show metadata for a single attachment.
86	     */
87	    public function show(Request $request, Attachment $attachment): JsonResponse
88	    {
89	        $this->authorize('view', $attachment);
90	
91	        return response()->json(['data' => $this->attachmentShape($attachment)]);
92	    }
93	
94	    /**
95	     * DELETE /api/v1/attachments/{attachment}
96	     *
97	     * Revoke an attachment (soft-delete, status set to revoked).
98	     */
99	    public function destroy(Request $request, Attachment $attachment): Response
100	    {
101	        $this->authorize('delete', $attachment);
102	
103	        $this->service->revokeAttachment($request->user(), $attachment, $request->ip());
104	
105	        return response()->noContent();
106	    }
107	
108	    // -------------------------------------------------------------------------
109	    // Private helpers
110	    // -------------------------------------------------------------------------
111	
112	    /**
113	     * Resolve a URL slug to a fully-qualified model class name.
114	     * Returns 422 if the type is not in the morph map.
115	     */
116	    private function resolveRecordType(string $type): string
117	    {
118	        if (!isset(self::MORPH_MAP[$type])) {
119	            abort(422, "Unknown record type '{$type}'. Allowed: " . implode(', ', array_keys(self::MORPH_MAP)));
120	        }
121	
122	        return self::MORPH_MAP[$type];
123	    }
124	
125	    private function attachmentShape(Attachment $attachment): array
126	    {
127	        return [
128	            'id'                 => $attachment->id,
129	            'record_type'        => $attachment->record_type,
