3	namespace App\Domain\Sales\Enums;
4	
5	enum SalesStatus: string
6	{
7	    case Draft     = 'draft';
8	    case Reviewed  = 'reviewed';
9	    case Completed = 'completed';
10	    case Voided    = 'voided';
11	
12	    /**
13	     * Whether this document can still be edited (line items, notes, etc.).
14	     */
15	    public function isEditable(): bool
16	    {
17	        return $this === self::Draft;
18	    }
19	
20	    /**
21	     * Whether outbound linkage is permitted for this document.
22	     * Outbound linkage requires final approval (completed state).
23	     */
24	    public function allowsOutboundLinkage(): bool
25	    {
26	        return $this === self::Completed;
27	    }
28	
29	    /**
30	     * Whether a return/exchange can be initiated against this document.
31	     */
32	    public function allowsReturn(): bool
33	    {
34	        return $this === self::Completed;
35	    }
36	
37	    /**
38	     * Whether this document can be voided.
39	     */
40	    public function canBeVoided(): bool
41	    {
42	        return match ($this) {
43	            self::Completed => false,  // Completed documents cannot be voided
44	            self::Voided    => false,  // Already voided
45	            default         => true,
46	        };
47	    }
48	
49	    /**
50	     * Valid transitions from this status.
51	     *
52	     * @return list<self>
53	     */
54	    public function allowedTransitions(): array
55	    {
56	        return match ($this) {
57	            self::Draft     => [self::Reviewed, self::Voided],
58	            self::Reviewed  => [self::Completed, self::Voided],
59	            self::Completed => [],  // Terminal — returns/exchanges handled separately
60	            self::Voided    => [],  // Terminal
61	        };
62	    }
63	
64	    public function canTransitionTo(self $target): bool
65	    {
66	        return in_array($target, $this->allowedTransitions(), strict: true);
67	    }
68	}
