3	namespace App\Application\Auth;
4	
5	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
6	use App\Domain\Audit\Enums\AuditAction;
7	use App\Domain\Auth\Contracts\UserRepositoryInterface;
8	use App\Domain\Auth\ValueObjects\LockoutPolicy;
9	use App\Exceptions\Auth\AccountLockedException;
10	use App\Models\FailedLoginAttempt;
11	use App\Models\User;
12	use Illuminate\Auth\AuthenticationException;
13	use Illuminate\Support\Facades\Hash;
14	use Illuminate\Support\Str;
15	
16	/**
17	 * Orchestrates username/password authentication with lockout enforcement.
18	 *
19	 * Responsibilities:
20	 *   - Locate user by username (case-insensitive)
21	 *   - Check account status (active / locked)
22	 *   - Verify password using bcrypt (Hash::check against password_hash column)
23	 *   - Track failed attempts; enforce 5-attempt → 15-minute lockout
24	 *   - Issue Sanctum bearer token on success
25	 *   - Write an audit event for every outcome (login, login_failed, lockout, logout)
26	 */
27	class AuthenticationService
28	{
29	    public function __construct(
30	        private readonly UserRepositoryInterface $users,
31	        private readonly AuditEventRepositoryInterface $audit,
32	    ) {}
33	
34	    /**
35	     * Attempt a login.
36	     *
37	     * @return array{token: string, user: User}
38	     *
39	     * @throws AuthenticationException  On bad credentials or inactive account
40	     * @throws AccountLockedException   When the account is within a lockout window
41	     */
42	    public function login(string $username, string $password, string $ipAddress): array
43	    {
44	        $user = $this->users->findByUsername($username);
45	
46	        // Unknown username
47	        if ($user === null) {
48	            $this->recordFailedAttempt(userId: null, usernameAttempted: $username, ip: $ipAddress);
49	            $this->recordAudit(
50	                action: AuditAction::LoginFailed,
51	                actorId: null,
52	                payload: ['username_attempted' => $username, 'reason' => 'user_not_found'],
53	                ip: $ipAddress,
54	            );
55	            throw new AuthenticationException('Invalid credentials.');
56	        }
57	
58	        // Inactive account — treated as unknown to avoid enumeration
59	        if (!$user->is_active) {
60	            $this->recordFailedAttempt(userId: $user->id, usernameAttempted: $username, ip: $ipAddress);
61	            $this->recordAudit(
62	                action: AuditAction::LoginFailed,
63	                actorId: $user->id,
64	                payload: ['reason' => 'account_inactive'],
65	                ip: $ipAddress,
66	            );
67	            throw new AuthenticationException('Invalid credentials.');
68	        }
69	
70	        // Locked account
71	        if ($this->users->isLocked($user->id)) {
72	            $lockedUntil = $user->locked_until?->toDateTimeImmutable();
73	            $this->recordFailedAttempt(userId: $user->id, usernameAttempted: $username, ip: $ipAddress);
74	            $this->recordAudit(
75	                action: AuditAction::LoginFailed,
76	                actorId: $user->id,
77	                payload: ['reason' => 'account_locked', 'locked_until' => $lockedUntil?->format(\DateTimeInterface::ATOM)],
78	                ip: $ipAddress,
79	            );
80	            throw new AccountLockedException($lockedUntil);
81	        }
82	
83	        // Wrong password
84	        if (!Hash::check($password, $user->password_hash)) {
85	            $this->recordFailedAttempt(userId: $user->id, usernameAttempted: $username, ip: $ipAddress);
86	            $this->users->incrementFailedAttempts($user->id);
87	
88	            // Reload to get the updated count
89	            $user->refresh();
90	
91	            if ($user->failed_attempt_count >= LockoutPolicy::MAX_ATTEMPTS) {
92	                $lockUntil  = (new \DateTimeImmutable())->modify(
93	                    '+' . LockoutPolicy::LOCKOUT_MINUTES . ' minutes'
94	                );
95	                $beforeHash = hash('sha256', json_encode($user->toArray())); // state before lock
96	                $this->users->lockUntil($user->id, $lockUntil);
97	                $afterHash  = hash('sha256', json_encode($user->fresh()->toArray())); // state after lock
98	
99	                $this->recordAudit(
100	                    action: AuditAction::Lockout,
101	                    actorId: $user->id,
102	                    payload: [
103	                        'reason'       => 'max_attempts_exceeded',
104	                        'attempts'     => $user->failed_attempt_count,
105	                        'locked_until' => $lockUntil->format(\DateTimeInterface::ATOM),
106	                    ],
107	                    ip: $ipAddress,
108	                    beforeHash: $beforeHash,
109	                    afterHash: $afterHash,
110	                );
111	            } else {
112	                $this->recordAudit(
113	                    action: AuditAction::LoginFailed,
114	                    actorId: $user->id,
115	                    payload: [
116	                        'reason'   => 'wrong_password',
117	                        'attempts' => $user->failed_attempt_count,
118	                    ],
119	                    ip: $ipAddress,
120	                );
121	            }
122	
123	            throw new AuthenticationException('Invalid credentials.');
124	        }
125	
126	        // Success — clear failed attempts and issue token
127	        $this->users->clearFailedAttempts($user->id);
128	        $user->refresh();
129	
130	        $token = $user->createToken('api')->plainTextToken;
131	
132	        $this->recordAudit(
133	            action: AuditAction::Login,
134	            actorId: $user->id,
135	            payload: [],
136	            ip: $ipAddress,
137	        );
138	
139	        return [
140	            'token' => $token,
141	            'user'  => $user->load('department'),
142	        ];
143	    }
144	
145	    /**
146	     * Revoke the current access token.
147	     */
148	    public function logout(User $user, string $ipAddress): void
149	    {
150	        $user->currentAccessToken()->delete();
151	
152	        $this->recordAudit(
153	            action: AuditAction::Logout,
154	            actorId: $user->id,
155	            payload: [],
156	            ip: $ipAddress,
157	        );
158	    }
159	
160	    // -------------------------------------------------------------------------
161	    // Private helpers
162	    // -------------------------------------------------------------------------
163	
164	    /**
165	     * Persist a failed login attempt record for admin inspection.
166	     * Called for every authentication failure regardless of reason.
167	     */
168	    private function recordFailedAttempt(?string $userId, string $usernameAttempted, string $ip): void
169	    {
170	        FailedLoginAttempt::create([
171	            'user_id'            => $userId,
172	            'username_attempted' => $usernameAttempted,
173	            'ip_address'         => $ip,
174	            'attempted_at'       => now(),
175	        ]);
176	    }
177	
178	    private function recordAudit(
179	        AuditAction $action,
180	        ?string $actorId,
181	        array $payload,
182	        string $ip,
183	        ?string $beforeHash = null,
184	        ?string $afterHash = null,
185	    ): void {
186	        // Auth events have no specific auditable model; propagate idempotency key for request linkage
187	        $idempotencyKey = request()->header('X-Idempotency-Key');
188	        $correlationId  = $idempotencyKey !== null
189	            ? hash('sha256', $idempotencyKey . ':auth:' . $action->value)
190	            : (string) Str::uuid();
191	
192	        $this->audit->record(
193	            correlationId:  $correlationId,
194	            action:         $action,
195	            actorId:        $actorId,
196	            auditableType:  null,
197	            auditableId:    null,
198	            beforeHash:     $beforeHash,
199	            afterHash:      $afterHash,
200	            payload:        $payload,
201	            ipAddress:      $ip,
202	        );
203	    }
204	}
