3	namespace App\Http\Middleware;
4	
5	use Closure;
6	use Illuminate\Http\Request;
7	use Symfony\Component\HttpFoundation\Response;
8	
9	/**
10	 * Masks the 'notes' field in JSON responses for users who lack cross-department
11	 * or system-wide permission scope.
12	 *
13	 * Users with admin or auditor roles always see unmasked notes.
14	 * All other users see [REDACTED] in place of notes values.
15	 *
16	 * This is an after-middleware — it modifies the response content.
17	 */
18	class MaskSensitiveFields
19	{
20	    public function handle(Request $request, Closure $next): Response
21	    {
22	        $response = $next($request);
23	
24	        // Only act on authenticated JSON responses
25	        if (!$request->user() || !$this->isJsonResponse($response)) {
26	            return $response;
27	        }
28	
29	        $user = $request->user();
30	
31	        // Admin and auditor roles always see unmasked data
32	        if ($user->hasRole(['admin', 'auditor'])) {
33	            return $response;
34	        }
35	
36	        // Users with manage_configuration or system-wide permissions see unmasked data
37	        // (i.e., those with cross_department or system_wide scope)
38	        if ($user->hasPermissionTo('manage configuration') ||
39	            $user->hasRole('manager')) {
40	            return $response;
41	        }
42	
43	        // Mask notes for staff, viewer, and any other role
44	        $content = json_decode($response->getContent(), associative: true);
45	
46	        if (is_array($content)) {
47	            $content = $this->maskNotes($content);
48	            $response->setContent(json_encode($content));
49	        }
50	
51	        return $response;
52	    }
53	
54	    /**
55	     * Recursively replace 'notes' values with '[REDACTED]' at any depth.
56	     */
57	    private function maskNotes(array $data): array
58	    {
59	        foreach ($data as $key => $value) {
60	            if ($key === 'notes' && $value !== null) {
61	                $data[$key] = '[REDACTED]';
62	            } elseif (is_array($value)) {
63	                $data[$key] = $this->maskNotes($value);
64	            }
65	        }
66	
67	        return $data;
68	    }
69	
70	    private function isJsonResponse(Response $response): bool
71	    {
72	        $contentType = $response->headers->get('Content-Type', '');
73	
74	        return str_contains($contentType, 'application/json');
75	    }
76	}
