3	namespace App\Policies;
4	
5	use App\Models\User;
6	use App\Models\WorkflowInstance;
7	
8	class WorkflowInstancePolicy
9	{
10	    /**
11	     * Admin bypasses all checks.
12	     */
13	    public function before(User $user, string $ability): ?bool
14	    {
15	        if ($user->hasRole('admin')) {
16	            return true;
17	        }
18	
19	        return null;
20	    }
21	
22	    /**
23	     * A user can list/view workflow instances if they have the view workflow permission.
24	     */
25	    public function viewAny(User $user): bool
26	    {
27	        return $user->can('view workflow');
28	    }
29	
30	    /**
31	     * A user can view a specific workflow instance if:
32	     *   - They have 'view workflow' permission AND
33	     *   - They are the initiator, OR assigned to any node in this instance,
34	     *     OR hold a supervisory role (admin/manager/manage workflow instances).
35	     */
36	    public function view(User $user, WorkflowInstance $instance): bool
37	    {
38	        if (!$user->can('view workflow')) {
39	            return false;
40	        }
41	
42	        // Supervisory roles see all instances
43	        if ($user->hasRole(['admin', 'manager']) || $user->can('manage workflow instances')) {
44	            return true;
45	        }
46	
47	        // Initiator can always view their own instance
48	        if ($instance->initiated_by === $user->id) {
49	            return true;
50	        }
51	
52	        // Assigned approvers can view instances containing their nodes
53	        return $instance->nodes()->where('assigned_to', $user->id)->exists();
54	    }
55	
56	    /**
57	     * A user can approve, reject, reassign, or add approvers on a workflow node if
58	     * they have the 'approve workflow nodes' permission.
59	     * Assignee ownership is enforced at the service layer (guardNodeActionable).
60	     */
61	    public function approve(User $user, WorkflowInstance $instance): bool
62	    {
63	        return $user->can('approve workflow nodes');
64	    }
65	}
