5	enum WorkflowStatus: string
6	{
7	    case Pending    = 'pending';
8	    case InProgress = 'in_progress';
9	    case Approved   = 'approved';
10	    case Rejected   = 'rejected';
11	    case Withdrawn  = 'withdrawn';
12	    case Expired    = 'expired';
13	
14	    /**
15	     * Terminal states — no further transitions possible.
16	     */
17	    public function isTerminal(): bool
18	    {
19	        return match ($this) {
20	            self::Approved, self::Rejected,
21	            self::Withdrawn, self::Expired => true,
22	            default                        => false,
23	        };
24	    }
25	
26	    /**
27	     * Whether the workflow/node is still in an actionable state.
28	     */
29	    public function isActionable(): bool
30	    {
31	        return match ($this) {
32	            self::Pending, self::InProgress => true,
33	            default                          => false,
34	        };
35	    }
36	
37	    /**
38	     * Whether withdrawal is permitted in this state.
39	     * Withdrawal is only allowed before final approval.
40	     */
41	    public function allowsWithdrawal(): bool
42	    {
43	        return $this->isActionable();
44	    }
45	
46	    /**
47	     * Valid transitions for an instance or node in this status.
48	     *
49	     * @return list<self>
50	     */
51	    public function allowedTransitions(): array
52	    {
53	        return match ($this) {
54	            self::Pending    => [self::InProgress, self::Withdrawn],
55	            self::InProgress => [self::Approved, self::Rejected, self::Withdrawn, self::Expired],
56	            default          => [],  // All terminal states have no outbound transitions
57	        };
58	    }
