3	namespace App\Http\Middleware;
4	
5	use App\Application\Idempotency\Contracts\IdempotencyServiceInterface;
6	use Closure;
7	use Illuminate\Http\Request;
8	use Symfony\Component\HttpFoundation\Response;
9	
10	/**
11	 * Enforces idempotency key requirements on all mutating HTTP methods.
12	 *
13	 * Behaviour:
14	 *   - GET, HEAD, OPTIONS requests pass through without any check
15	 *   - POST, PUT, PATCH, DELETE: X-Idempotency-Key header is required
16	 *   - Key must be a valid UUID v4
17	 *   - If a cached response exists for the key, return it immediately with
18	 *     X-Idempotency-Replay: true header
19	 *   - After a successful (non-cached) response, persist the response body
20	 *     and status code for 24 hours
21	 */
22	class IdempotencyMiddleware
23	{
24	    private const MUTATING_METHODS = ['POST', 'PUT', 'PATCH', 'DELETE'];
25	
26	    public function __construct(
27	        private readonly IdempotencyServiceInterface $idempotency,
28	    ) {}
29	
30	    public function handle(Request $request, Closure $next): Response
31	    {
32	        // Read-only methods do not require idempotency keys
33	        if (!in_array($request->method(), self::MUTATING_METHODS, strict: true)) {
34	            return $next($request);
35	        }
36	
37	        $key = $request->header('X-Idempotency-Key');
38	
39	        // Header is missing
40	        if ($key === null || $key === '') {
41	            return $this->errorResponse(
42	                code: 'idempotency_key_required',
43	                message: 'Mutating requests must include an X-Idempotency-Key header (UUID v4).',
44	                status: 422,
45	            );
46	        }
47	
48	        // Header has an invalid format
49	        if (!$this->idempotency->isValidKey($key)) {
50	            return $this->errorResponse(
51	                code: 'idempotency_key_invalid',
52	                message: 'The X-Idempotency-Key header must be a valid UUID v4.',
53	                status: 422,
54	            );
55	        }
56	
57	        // Return cached response if one exists — scoped to this method + path
58	        $cached = $this->idempotency->getCachedResponse($key, $request->method(), $request->path());
59	
60	        if ($cached !== null) {
61	            return response()
62	                ->json($cached['body'], $cached['status'])
63	                ->header('X-Idempotency-Replay', 'true');
64	        }
65	
66	        // Process the request normally
67	        $response = $next($request);
68	
69	        // Persist the response body for future replay (only for success/4xx; not 5xx)
70	        if ($response->getStatusCode() < 500) {
71	            $body = json_decode($response->getContent(), associative: true) ?? [];
72	            $this->idempotency->storeResponse(
73	                $key,
74	                $response->getStatusCode(),
75	                $body,
76	                $request->method(),
77	                $request->path(),
78	            );
79	        }
80	
81	        return $response;
82	    }
83	
84	    private function errorResponse(string $code, string $message, int $status): Response
85	    {
86	        return response()->json([
87	            'error' => [
88	                'code'    => $code,
89	                'message' => $message,
90	                'details' => (object) [],
91	            ],
92	        ], $status);
93	    }
94	}
