17	        }
18	
19	        return null;
20	    }
21	
22	    /**
23	     * A user can view a return record if they can view sales and their department
24	     * matches the parent SalesDocument's department (or they have cross-department scope).
25	     */
26	    public function view(User $user, ReturnRecord $returnRecord): bool
27	    {
28	        $hasPermission = $user->can('view sales') || $user->can('manage sales');
29	
30	        if (!$hasPermission) {
31	            return false;
32	        }
33	
34	        if ($this->hasCrossScope($user)) {
35	            return true;
36	        }
37	
38	        // Scope to department via the parent sales document
39	        $salesDocument = $returnRecord->salesDocument;
40	
41	        if ($salesDocument === null) {
42	            return false;
43	        }
44	
45	        return $user->department_id !== null
46	            && $user->department_id === $salesDocument->department_id;
47	    }
48	
49	    // -------------------------------------------------------------------------
50	    // Shared helpers
51	    // -------------------------------------------------------------------------
52	
53	    protected function hasCrossScope(User $user): bool
54	    {
55	        return $user->hasRole(['manager', 'auditor']);
