3	namespace App\Http\Controllers\Api\Admin;
4	
5	use App\Application\Metrics\MetricsRetentionService;
6	use App\Http\Controllers\Controller;
7	use App\Models\MetricsSnapshot;
8	use Illuminate\Http\JsonResponse;
9	use Illuminate\Http\Request;
10	use Illuminate\Support\Facades\DB;
11	
12	/**
13	 * Admin endpoint for metrics snapshot retrieval and summary.
14	 *
15	 * Metric types:
16	 *   - request_timing    p95 request duration samples (ms)
17	 *   - queue_depth       snapshot of queued job count
18	 *   - failed_approvals  count of workflow nodes that expired or were rejected
19	 *
20	 * Authorization: admin role only.
21	 */
22	class MetricsController extends Controller
23	{
24	    public function __construct(
25	        private readonly MetricsRetentionService $metrics,
26	    ) {}
27	
28	    /**
29	     * GET /api/v1/admin/metrics
30	     *
31	     * Retrieve metrics snapshots with optional filters and optional summary mode.
32	     *
33	     * Query params:
34	     *   - metric_type   Filter by type: request_timing | queue_depth | failed_approvals
35	     *   - date_from     ISO-8601 lower bound for recorded_at (inclusive)
36	     *   - date_to       ISO-8601 upper bound for recorded_at (inclusive)
37	     *   - summary       If '1' or 'true', return aggregated summary instead of raw rows
38	     *   - per_page      Items per page when not in summary mode (1–500, default 100)
39	     */
40	    public function index(Request $request): JsonResponse
41	    {
42	        if (!$request->user()->hasRole('admin')) {
43	            abort(403, 'Admin role required to view metrics.');
44	        }
45	
46	        $query = MetricsSnapshot::query();
47	
48	        if ($request->has('metric_type')) {
49	            $query->where('metric_type', $request->input('metric_type'));
50	        }
51	
52	        if ($request->has('date_from')) {
53	            $query->where('recorded_at', '>=', $request->input('date_from'));
54	        }
55	
56	        if ($request->has('date_to')) {
57	            $query->where('recorded_at', '<=', $request->input('date_to'));
58	        }
59	
60	        if (filter_var($request->input('summary', false), FILTER_VALIDATE_BOOLEAN)) {
61	            return $this->summaryResponse($query);
62	        }
63	
64	        $perPage   = min((int) $request->input('per_page', 100), 500);
65	        $paginated = $query->orderBy('recorded_at', 'desc')->paginate($perPage);
66	
67	        return response()->json([
68	            'data' => $paginated->map(fn(MetricsSnapshot $s) => $this->snapshotShape($s)),
69	            'meta' => [
70	                'retention_days' => (int) config('meridian.retention.metrics_days', 90),
71	                'pagination'     => [
72	                    'current_page' => $paginated->currentPage(),
73	                    'per_page'     => $paginated->perPage(),
74	                    'total'        => $paginated->total(),
75	                    'last_page'    => $paginated->lastPage(),
76	                ],
77	            ],
78	        ]);
79	    }
80	
81	    // -------------------------------------------------------------------------
82	    // Private helpers
83	    // -------------------------------------------------------------------------
84	
85	    /**
86	     * Return aggregated summary grouped by metric_type.
87	     */
88	    private function summaryResponse($query): JsonResponse
89	    {
90	        $summaries = (clone $query)
91	            ->select('metric_type',
92	                DB::raw('COUNT(*) as sample_count'),
93	                DB::raw('AVG(value) as avg_value'),
94	                DB::raw('MIN(value) as min_value'),
95	                DB::raw('MAX(value) as max_value'),
96	                DB::raw('MAX(recorded_at) as last_recorded_at')
97	            )
98	            ->groupBy('metric_type')
99	            ->get();
100	
101	        return response()->json([
102	            'data' => $summaries->map(fn($row) => [
103	                'metric_type'     => $row->metric_type,
104	                'sample_count'    => (int) $row->sample_count,
105	                'avg_value'       => round((float) $row->avg_value, 4),
106	                'min_value'       => (float) $row->min_value,
107	                'max_value'       => (float) $row->max_value,
108	                'last_recorded_at' => $row->last_recorded_at,
109	            ]),
110	        ]);
111	    }
112	
113	    private function snapshotShape(MetricsSnapshot $snapshot): array
114	    {
115	        return [
116	            'id'             => $snapshot->id,
117	            'metric_type'    => $snapshot->metric_type,
118	            'value'          => $snapshot->value,
119	            'labels'         => $snapshot->labels,
120	            'recorded_at'    => $snapshot->recorded_at?->toIso8601String(),
121	            'retained_until' => $snapshot->retained_until?->toIso8601String(),
122	        ];
123	    }
124	}
