104	    /**
105	     * Transition draft → reviewed.
106	     */
107	    public function submit(User $user, SalesDocument $doc, string $ipAddress): SalesDocument
108	    {
109	        if (!$doc->status->canTransitionTo(SalesStatus::Reviewed)) {
110	            throw new InvalidSalesTransitionException($doc->status->value, SalesStatus::Reviewed->value);
111	        }
112	
113	        $beforeHash = hash('sha256', json_encode($doc->toArray()));
114	        $doc->update([
115	            'status'      => SalesStatus::Reviewed,
116	            'reviewed_by' => $user->id,
117	            'reviewed_at' => now(),
118	        ]);
119	        $afterHash = hash('sha256', json_encode($doc->fresh()->toArray()));
120	
121	        $this->recordAudit(AuditAction::SalesSubmit, $user->id, SalesDocument::class, $doc->id, $ipAddress, beforeHash: $beforeHash, afterHash: $afterHash);
122	
123	        return $doc->fresh()->load(['department', 'createdBy', 'lineItems']);
124	    }
