127	     * Transition reviewed → completed and create stock-out inventory movements.
128	     */
129	    public function complete(User $user, SalesDocument $doc, string $ipAddress): SalesDocument
130	    {
131	        if (!$doc->status->canTransitionTo(SalesStatus::Completed)) {
132	            throw new InvalidSalesTransitionException($doc->status->value, SalesStatus::Completed->value);
133	        }
