public function store(StoreAttachmentRequest $request, string $type, string $id): JsonResponse
{
    $recordType = $this->resolveRecordType($type);
    $record = $recordType::findOrFail($id);
    $this->authorize('view', $record);           // parent-scope authorization

    $files = $request->file('files');
    $existingCount = \App\Models\Attachment::where('record_type', $recordType)
        ->where('record_id', $id)
        ->whereNull('deleted_at')
        ->count();

    if ($existingCount + count($files) > \App\Domain\Attachment\ValueObjects\FileConstraints::MAX_FILES_PER_RECORD) {
        abort(422, 'Batch upload would exceed the 20-file limit for this record.');
    }

    $results = [];
    foreach ($files as $file) {
