        $doc = createDraftDoc($this->manager, $this->dept);

        Sanctum::actingAs($this->manager);

        $this->postJson("/api/v1/sales/{$doc['id']}/submit")->assertStatus(200);
        $this->postJson("/api/v1/sales/{$doc['id']}/complete")->assertStatus(200);

        // No workflow instance linked — completed status alone is sufficient
        $response = $this->postJson("/api/v1/sales/{$doc['id']}/link-outbound");

        $response->assertStatus(200);
        expect($response->json('data.outbound_linked_at'))->not->toBeNull();
    });

    it('returns 409 when outbound linkage is attempted on a document with a non-approved workflow instance', function () {
        $doc = createDraftDoc($this->manager, $this->dept);

        Sanctum::actingAs($this->manager);

        $this->postJson("/api/v1/sales/{$doc['id']}/submit")->assertStatus(200);
        $this->postJson("/api/v1/sales/{$doc['id']}/complete")->assertStatus(200);

        // Create a workflow template and link an in-progress (non-approved) instance
        $template = WorkflowTemplate::create([
            'name'       => 'Outbound Approval',
            'event_type' => 'sales_outbound',
            'is_active'  => true,
            'created_by' => $this->manager->id,
        ]);
        $wfInstance = WorkflowInstance::create([
            'workflow_template_id' => $template->id,
            'record_type'          => SalesDocument::class,
            'record_id'            => $doc['id'],
            'status'               => WorkflowStatus::InProgress->value,
            'initiated_by'         => $this->manager->id,
            'started_at'           => now(),
        ]);

        // Link the non-approved workflow instance to the sales document
        SalesDocument::where('id', $doc['id'])->update(['workflow_instance_id' => $wfInstance->id]);

        $response = $this->postJson("/api/v1/sales/{$doc['id']}/link-outbound");

        // Workflow linked but not in Approved state → 409
        $response->assertStatus(409)
                 ->assertJsonPath('error.code', 'outbound_linkage_not_allowed');
    });
});"}

