        // 20 targets out of 100 eligible → 20% → exceeds 10% cap
        $targetIds = array_map(fn() => Str::uuid()->toString(), range(1, 20));

        $response = $this->postJson("/api/v1/configuration/versions/{$versionId}/rollout", [
            'target_type'    => 'store',
