3	namespace App\Domain\Auth\ValueObjects;
4	
5	/**
6	 * Enforces password complexity rules for the Meridian system.
7	 *
8	 * Rules (from original prompt):
9	 *   - Minimum 12 characters
10	 *   - At least 1 uppercase letter
11	 *   - At least 1 lowercase letter
12	 *   - At least 1 digit
13	 *
14	 * This is an immutable value object — no state, static interface only.
15	 */
16	final class PasswordPolicy
17	{
18	    public const MIN_LENGTH = 12;
19	
20	    private function __construct() {}
21	
22	    /**
23	     * Check whether the given plaintext password satisfies all rules.
24	     */
25	    public static function validate(string $password): bool
26	    {
27	        return self::violations($password) === [];
28	    }
29	
30	    /**
31	     * Return all violated rule messages for the given password.
32	     * Empty array means the password is valid.
33	     *
34	     * @return list<string>
35	     */
36	    public static function violations(string $password): array
37	    {
38	        $violations = [];
39	
40	        if (mb_strlen($password) < self::MIN_LENGTH) {
41	            $violations[] = 'Password must be at least ' . self::MIN_LENGTH . ' characters long.';
42	        }
43	
44	        if (!preg_match('/[A-Z]/', $password)) {
45	            $violations[] = 'Password must contain at least one uppercase letter.';
46	        }
47	
48	        if (!preg_match('/[a-z]/', $password)) {
49	            $violations[] = 'Password must contain at least one lowercase letter.';
50	        }
51	
52	        if (!preg_match('/[0-9]/', $password)) {
53	            $violations[] = 'Password must contain at least one digit.';
54	        }
55	
56	        return $violations;
57	    }
58	
59	    /**
60	     * Return a human-readable description of the password requirements.
61	     */
62	    public static function requirements(): string
63	    {
64	        return sprintf(
65	            'Password must be at least %d characters long and contain at least one uppercase letter, one lowercase letter, and one digit.',
66	            self::MIN_LENGTH
67	        );
68	    }
69	}
