     *
     * Requires: document must be in Completed status AND, if a workflow instance is
     * linked to the document, that instance must be in the terminal Approved state.
     */
    public function linkOutbound(User $user, SalesDocument $doc, string $ipAddress): SalesDocument
    {
        if (!$doc->status->allowsOutboundLinkage()) {
            throw new OutboundLinkageNotAllowedException();
        }

        // If a workflow instance is linked, enforce that it reached terminal Approved state.
        // Documents without a linked workflow may proceed on Completed status alone.
        if ($doc->workflow_instance_id !== null) {
            $doc->loadMissing('workflowInstance');
            if ($doc->workflowInstance === null
                || $doc->workflowInstance->status !== \App\Domain\Workflow\Enums\WorkflowStatus::Approved) {
                throw new OutboundLinkageNotAllowedException(
                    'The linked workflow instance must be in Approved state before outbound linkage.'
