   - Workflow approval gate enforcement in `SalesDocumentService::linkOutbound()`
   - Laravel `WorkflowStatus` enum with `Approved`, `InProgress`, `Rejected`, `Withdrawn`, `RolledBack` values
   - `OutboundLinkageNotAllowedException` thrown when workflow gate fails
   - Static-only audit re-check (no Docker/migrations/test execution)

3. Files and Code Sections:

   - **`api_tests/Attachment/AttachmentUploadTest.php`**
     - T6 completion: all remaining `['file' => $file]` changed to `['files' => [$file]]`; `data.id` / `data.mime_type` / `data.status` assertions updated to `data.0.id` / `data.0.mime_type` / `data.0.status`; two new department-scope tests added; misplaced "Revocation" section header renamed to "Upload and delete department scope"
     - Key additions:
     ```php
     it('returns 403 when a user from a different department uploads to a record in another department', function () {
         $otherDept = Department::create(['name' => 'Legal', 'code' => 'LGL']);
         $outsider = User::create([...]);
         $outsider->assignRole('staff');
         Sanctum::actingAs($outsider, ['*'], 'sanctum');
         $file = UploadedFile::fake()->create('outsider.pdf', 100, 'application/pdf');
         $response = $this->postJson(
             "/api/v1/records/document/{$this->doc->id}/attachments",
             ['files' => [$file]],
             ['X-Idempotency-Key' => Str::uuid()->toString()]
         );
         $response->assertStatus(403);
     });

     it('returns 403 when a user from a different department tries to delete an attachment', function () {
         Sanctum::actingAs($this->staff, ['*'], 'sanctum');
         $file = UploadedFile::fake()->create('to_delete.pdf', 100, 'application/pdf');
         $upload = $this->postJson(..., ['files' => [$file]], ...);
         $upload->assertStatus(201);
         $attachmentId = $upload->json('data.0.id');
         $outsider = User::create([...department_id => $otherDept->id...]);
         $outsider->givePermissionTo('revoke attachments');
         Sanctum::actingAs($outsider, ['*'], 'sanctum');
         $response = $this->deleteJson("/api/v1/attachments/{$attachmentId}", [], [...]);
         $response->assertStatus(403); // Has permission but wrong department
     });
     ```

   - **`api_tests/Admin/AdminMetricsTest.php`**
     - T7: Added `use Illuminate\Support\Str;` import; added two producer-path tests verifying metrics are written by application flows (not just seeded)
     ```php
     it('records a request_timing snapshot after each authenticated request via middleware', function () {
         Sanctum::actingAs($this->admin);
         $countBefore = MetricsSnapshot::where('metric_type', 'request_timing')->count();
         $this->getJson('/api/v1/admin/health')->assertStatus(200);
         $countAfter = MetricsSnapshot::where('metric_type', 'request_timing')->count();
         expect($countAfter)->toBeGreaterThan($countBefore);
     });

     it('records a failed_approvals snapshot when a workflow node is rejected', function () {
         $this->admin->givePermissionTo([
             'manage workflow templates', 'manage workflow instances',
             'approve workflow nodes', 'view workflow',
         ]);
         Sanctum::actingAs($this->admin);
         $templateResponse = $this->postJson('/api/v1/workflow/templates', [
             'name' => 'Metrics Producer Template', 'event_type' => 'metrics_test',
             'nodes' => [['node_type' => 'sequential', 'node_order' => 1, 'label' => 'Review']],
         ]);
         $templateId = $templateResponse->json('data.id');
         $instanceResponse = $this->postJson('/api/v1/workflow/instances', [
             'workflow_template_id' => $templateId,
             'record_type' => 'metrics_test',
             'record_id' => Str::uuid()->toString(), 'context' => [],
         ]);
         $nodeId = $instanceResponse->json('data.nodes.0.id');
         $countBefore = MetricsSnapshot::where('metric_type', 'failed_approvals')->count();
         $this->postJson("/api/v1/workflow/nodes/{$nodeId}/reject", [
             'reason' => 'Test rejection for metrics instrumentation.',
         ])->assertStatus(200);
         $countAfter = MetricsSnapshot::where('metric_type', 'failed_approvals')->count();
         expect($countAfter)->toBeGreaterThan($countBefore);
