     - T8: Full new test suite for admin user creation and password reset with PasswordPolicy enforcement
     ```php
     describe('Admin User Management', function () {
         it('allows admin to create a user with a valid password and returns 201', ...);
         it('returns 422 with PasswordPolicy violation messages when password is too short', function () {
             Sanctum::actingAs($this->admin);
             $response = $this->postJson('/api/v1/admin/users', [
                 'username' => 'weak_pwd_short', 'display_name' => 'Weak Short',
