         it('returns 422 ... when password lacks uppercase and digit', ...);
         it('returns 403 when a non-admin user tries to create a user', ...);
         it('allows admin to reset a user password with a valid password and returns 200', ...);
         it('returns 422 ... when resetting to a weak password', ...);
         it('returns 403 when a non-admin user tries to reset a password', ...);
