447	    /**
448	     * Guard that a node is in an actionable state, its instance is not terminal,
449	     * and the acting user is the assigned approver (or holds a supervisory role).
450	     *
451	     * @throws AuthorizationException             If user is not the assigned approver
452	     * @throws WorkflowNodeNotActionableException If node is not in an actionable state
453	     * @throws WorkflowTerminatedException        If the parent instance is already terminal
454	     */
455	    private function guardNodeActionable(WorkflowNode $node, User $user): void
456	    {
457	        // Object-level assignee check: only the assigned user (or supervisors) may act on a node
458	        if ($node->assigned_to !== null
459	            && $node->assigned_to !== $user->id
460	            && !$user->hasRole(['admin', 'manager'])
461	            && !$user->can('manage workflow instances')
462	        ) {
463	            throw new AuthorizationException('You are not the assigned approver for this workflow node.');
464	        }
465	
466	        if (!$node->status->isActionable()) {
467	            throw new WorkflowNodeNotActionableException();
468	        }
469	
470	        if ($node->instance->status->isTerminal()) {
471	            throw new WorkflowTerminatedException();
472	        }
473	    }
