475	    /**
476	     * Evaluate a conditional node's branch condition against the context data.
477	     *
478	     * Returns true if no condition is configured (unconditional node).
479	     * Supported operators: gt, lt, eq, gte, lte.
480	     */
481	    private function evaluateCondition(WorkflowTemplateNode $node, array $contextData): bool
482	    {
483	        if (empty($node->condition_field)) {
484	            return true;
485	        }
486	
487	        $fieldValue    = $contextData[$node->condition_field] ?? null;
488	        $condValue     = $node->condition_value;
489	        $condOperator  = $node->condition_operator;
490	
491	        if ($fieldValue === null || $condValue === null || $condOperator === null) {
492	            return true;
493	        }
494	
495	        return match ($condOperator) {
496	            'gt'    => $fieldValue > $condValue,
497	            'lt'    => $fieldValue < $condValue,
498	            'eq'    => $fieldValue == $condValue,
499	            'gte'   => $fieldValue >= $condValue,
500	            'lte'   => $fieldValue <= $condValue,
501	            default => true,
502	        };
503	    }
