506	     * Resolve the first available user with the given role (and optionally department).
507	     *
508	     * Returns null if no matching user is found — the node will have assigned_to=null.
509	     */
510	    private function resolveRoleAssignee(?string $roleId, ?string $departmentId): ?string
511	    {
512	        if ($roleId === null) {
513	            return null;
514	        }
515	
516	        $query = User::whereHas('roles', fn($q) => $q->where('id', $roleId))
517	            ->where('is_active', true);
518	
519	        if ($departmentId !== null) {
520	            $query->where('department_id', $departmentId);
521	        }
522	
523	        return $query->value('id');
524	    }
