34	    /**
35	     * Find the next pending node after a given node_order position.
36	     *
37	     * Used to advance the workflow after a sequential or parallel node completes.
38	     */
39	    public function findNextPendingNode(string $instanceId, int $afterOrder): ?WorkflowNode
40	    {
41	        return WorkflowNode::where('workflow_instance_id', $instanceId)
42	            ->where('node_order', '>', $afterOrder)
43	            ->where('status', WorkflowStatus::Pending->value)
44	            ->orderBy('node_order')
45	            ->first();
46	    }
