48	    /**
49	     * Check whether all nodes at a given node_order position within an instance
50	     * have been approved. Used for parallel sign-off gating.
51	     *
52	     * A parallel group is "fully approved" when every node at that order level
53	     * has status=Approved (including the one being approved right now, so the
54	     * check must be called AFTER updating the current node's status).
55	     */
56	    public function allParallelNodesApproved(string $instanceId, int $nodeOrder): bool
57	    {
58	        $total = WorkflowNode::where('workflow_instance_id', $instanceId)
59	            ->where('node_order', $nodeOrder)
60	            ->count();
61	
62	        if ($total === 0) {
63	            return false;
64	        }
65	
66	        $approved = WorkflowNode::where('workflow_instance_id', $instanceId)
67	            ->where('node_order', $nodeOrder)
68	            ->where('status', WorkflowStatus::Approved->value)
69	            ->count();
70	
71	        return $approved === $total;
72	    }
