234	            throw new LinkRevokedException();
235	        }
236	
237	        if ($this->expiry->isLinkConsumed($link)) {
238	            throw new LinkConsumedException();
239	        }
240	
241	        // Optional IP restriction enforcement
242	        if ($link->ip_restriction !== null && $link->ip_restriction !== $requestIp) {
243	            abort(403, 'IP address not permitted for this link.');
244	        }
245	
246	        $attachment = $link->attachment;
247	
248	        if ($this->expiry->isAttachmentExpired($attachment)) {
249	            throw new AttachmentExpiredException();
250	        }
251	
252	        if ($attachment->status === AttachmentStatus::Revoked) {
253	            throw new AttachmentRevokedException();
254	        }
255	
256	        // Decrypt path → read encrypted file envelope → decrypt content
257	        $pathData     = json_decode($attachment->encrypted_path, true);
258	        $relativePath = $this->encryption->decrypt(
259	            $pathData['ciphertext'],
260	            $pathData['iv'],
261	            $pathData['key_id']
262	        );
263	
264	        $fileEnvelope = json_decode(Storage::disk('local')->get($relativePath), true);
265	        $plaintext    = $this->encryption->decrypt(
266	            $fileEnvelope['ciphertext'],
267	            $fileEnvelope['iv'],
268	            $fileEnvelope['key_id']
269	        );
270	
271	        // Atomically consume single-use links
272	        if ($link->is_single_use) {
273	            // Use the link creator as the consumed_by reference — resolution is unauthenticated
274	            $this->attachments->consumeLink($link->id, $link->created_by);
275	        }
276	
277	        // Record a LinkConsume audit event for every resolution (not just single-use)
278	        $this->recordAudit(AuditAction::LinkConsume, null, AttachmentLink::class, $link->id, $requestIp);
279	
280	        return [
281	            'content'   => $plaintext,
282	            'mime_type' => $attachment->mime_type,
283	            'filename'  => $attachment->original_filename,
284	        ];
285	    }
