3	namespace App\Infrastructure\Persistence;
4	
5	use App\Domain\Attachment\Contracts\AttachmentRepositoryInterface;
6	use App\Domain\Attachment\Enums\AttachmentStatus;
7	use App\Models\Attachment;
8	use App\Models\AttachmentLink;
9	use Illuminate\Support\Facades\DB;
10	
11	/**
12	 * Eloquent implementation of AttachmentRepositoryInterface.
13	 *
14	 * CRITICAL INVARIANTS:
15	 *   - consumeLink() uses lockForUpdate() — atomic single-use consumption
16	 *   - fingerprintExists() is a GLOBAL check (cross-record), not per-record
17	 *   - countActiveForRecord() excludes soft-deleted attachments
18	 */
19	class EloquentAttachmentRepository implements AttachmentRepositoryInterface
20	{
21	    /**
22	     * Find an attachment by its UUID.
23	     */
24	    public function findById(string $id): mixed
25	    {
26	        return Attachment::find($id);
27	    }
28	
29	    /**
30	     * Find an attachment link by its opaque token.
31	     * Eagerly loads the parent attachment for downstream access.
32	     */
33	    public function findLinkByToken(string $token): mixed
34	    {
35	        return AttachmentLink::where('token', $token)
36	            ->with('attachment')
37	            ->first();
38	    }
39	
40	    /**
41	     * Count active (non-revoked, non-expired, non-soft-deleted) attachments for a record.
42	     *
43	     * @param string $recordType Morph type string (e.g. 'App\Models\Document')
44	     * @param string $recordId   Record UUID
45	     */
46	    public function countActiveForRecord(string $recordType, string $recordId): int
47	    {
48	        return Attachment::where('record_type', $recordType)
49	            ->where('record_id', $recordId)
50	            ->where('status', AttachmentStatus::Active->value)
51	            ->whereNull('deleted_at')
52	            ->count();
53	    }
54	
55	    /**
56	     * Atomically consume a single-use link.
57	     *
58	     * Uses SELECT FOR UPDATE to prevent concurrent consumption.
59	     * Returns false if the link was already consumed or does not exist.
60	     */
61	    public function consumeLink(string $linkId, string $consumedByUserId): bool
62	    {
63	        return DB::transaction(function () use ($linkId, $consumedByUserId) {
64	            $link = AttachmentLink::lockForUpdate()->find($linkId);
65	
66	            if ($link === null || $link->consumed_at !== null) {
67	                return false;
68	            }
69	
70	            $link->update([
71	                'consumed_at' => now(),
72	                'consumed_by' => $consumedByUserId,
73	            ]);
74	
75	            return true;
76	        });
77	    }
78	
79	    /**
80	     * Check whether a SHA-256 fingerprint already exists for deduplication.
81	     *
82	     * NOTE: This is a GLOBAL check — it is not scoped to any particular record.
83	     * Identical content uploaded to different records is still detected as a duplicate.
84	     */
85	    public function fingerprintExists(string $sha256Fingerprint): bool
86	    {
87	        return Attachment::where('sha256_fingerprint', $sha256Fingerprint)->exists();
88	    }
89	}
