3	namespace App\Jobs;
4	
5	use App\Application\Backup\BackupMetadataService;
6	use App\Application\Logging\StructuredLogger;
7	use App\Domain\Audit\Contracts\AuditEventRepositoryInterface;
8	use App\Domain\Audit\Enums\AuditAction;
9	use Illuminate\Bus\Queueable;
10	use Illuminate\Contracts\Queue\ShouldQueue;
11	use Illuminate\Foundation\Bus\Dispatchable;
12	use Illuminate\Queue\InteractsWithQueue;
13	use Illuminate\Queue\SerializesModels;
14	use Illuminate\Support\Facades\DB;
15	use Illuminate\Support\Facades\Storage;
16	use Illuminate\Support\Str;
17	
18	/**
19	 * Orchestrates the daily local backup.
20	 *
21	 * This job:
22	 *   1. Creates a pending BackupJob record via BackupMetadataService
23	 *   2. Executes mysqldump and writes a compressed .sql.gz to storage/app/backups/
24	 *   3. Builds a manifest (dump path, table row-count summary, attachment inventory)
25	 *   4. Marks the job success/failed with manifest + size_bytes
26	 *   5. Records a BackupRun audit event
27	 *
28	 * The backup artifact is stored locally under storage/app/backups/ using the
29	 * naming convention: YYYY-MM-DD-{short-job-id}.sql.gz
30	 *
31	 * Database credentials are passed to mysqldump via a temporary options file
32	 * (never on the command line) to avoid exposure in process listings.
33	 */
34	class RunBackupJob implements ShouldQueue
35	{
36	    use Dispatchable, InteractsWithQueue, Queueable, SerializesModels;
37	
38	    public function __construct(
39	        private readonly bool $isManual = false,
40	    ) {}
41	
42	    public function handle(
43	        BackupMetadataService $metadata,
44	        AuditEventRepositoryInterface $audit,
45	        StructuredLogger $logger,
46	    ): void {
47	        $job = $metadata->startBackup($this->isManual);
48	
49	        try {
50	            $metadata->markRunning($job->id);
51	            $logger->info('Backup started', ['job_id' => $job->id, 'is_manual' => $this->isManual], 'backup');
52	
53	            $dumpPath  = $this->executeDump($job->id);
54	            $manifest  = $this->buildManifest($dumpPath);
55	            $sizeBytes = $this->estimateSizeBytes($manifest);
56	
57	            $metadata->completeBackup($job->id, $manifest, $sizeBytes);
58	            $logger->info('Backup completed', [
59	                'job_id'     => $job->id,
60	                'size_bytes' => $sizeBytes,
61	                'tables'     => count($manifest['tables'] ?? []),
62	                'files'      => $manifest['attachment_file_count'] ?? 0,
63	            ], 'backup');
64	
65	            $audit->record(
66	                correlationId:  (string) Str::uuid(),
67	                action:         AuditAction::BackupRun,
68	                actorId:        null,
69	                auditableType:  'BackupJob',
70	                auditableId:    $job->id,
71	                beforeHash:     null,
72	                afterHash:      null,
73	                payload:        ['status' => 'success', 'size_bytes' => $sizeBytes, 'is_manual' => $this->isManual],
74	                ipAddress:      '127.0.0.1',
75	            );
76	        } catch (\Throwable $e) {
77	            $metadata->failBackup($job->id, $e->getMessage());
78	            $logger->error('Backup failed', ['job_id' => $job->id, 'error' => $e->getMessage()], 'backup');
79	
80	            $audit->record(
81	                correlationId:  (string) Str::uuid(),
82	                action:         AuditAction::BackupRun,
83	                actorId:        null,
84	                auditableType:  'BackupJob',
85	                auditableId:    $job->id,
86	                beforeHash:     null,
87	                afterHash:      null,
88	                payload:        ['status' => 'failed', 'error' => $e->getMessage()],
89	                ipAddress:      '127.0.0.1',
90	            );
91	
92	            throw $e;
93	        }
94	    }
95	
96	    // -------------------------------------------------------------------------
97	    // Database dump
98	    // -------------------------------------------------------------------------
99	
100	    /**
101	     * Execute mysqldump and write a gzip-compressed dump file to storage/app/backups/.
102	     *
103	     * Uses a temporary MySQL options file for credentials to avoid exposing the
104	     * password in process listings (ps, /proc/*/cmdline). The options file is
105	     * removed immediately after mysqldump completes regardless of outcome.
106	     *
107	     * @param string $jobId UUID of the BackupJob record (used in filename)
108	     * @return string        Absolute path to the created .sql.gz file
109	     *
110	     * @throws \RuntimeException If mysqldump exits with a non-zero code
111	     */
112	    private function executeDump(string $jobId): string
113	    {
114	        $dbHost     = config('database.connections.mysql.host', '127.0.0.1');
115	        $dbPort     = config('database.connections.mysql.port', 3306);
116	        $dbName     = config('database.connections.mysql.database');
117	        $dbUser     = config('database.connections.mysql.username');
118	        $dbPassword = config('database.connections.mysql.password', '');
119	
120	        $backupDir = Storage::disk('local')->path('backups');
121	        if (!is_dir($backupDir)) {
122	            mkdir($backupDir, 0755, true);
123	        }
124	
125	        $filename = date('Y-m-d') . '-' . substr($jobId, 0, 8) . '.sql.gz';
126	        $dumpPath = $backupDir . '/' . $filename;
127	
128	        // Write credentials to a temp options file (mode 0600 — owner-readable only)
129	        $optFile = tempnam(sys_get_temp_dir(), 'meridian_bk_');
130	        file_put_contents($optFile, implode("\n", [
131	            '[client]',
132	            'password=' . $dbPassword,
133	        ]));
134	        chmod($optFile, 0600);
135	
136	        try {
137	            $command = sprintf(
138	                'mysqldump --defaults-extra-file=%s --host=%s --port=%s --user=%s'
139	                . ' --single-transaction --routines --triggers --skip-lock-tables %s'
140	                . ' | gzip > %s',
141	                escapeshellarg($optFile),
142	                escapeshellarg((string) $dbHost),
143	                escapeshellarg((string) $dbPort),
144	                escapeshellarg((string) $dbUser),
145	                escapeshellarg((string) $dbName),
146	                escapeshellarg($dumpPath),
147	            );
148	
149	            $output     = [];
150	            $returnCode = 0;
151	            exec($command . ' 2>&1', $output, $returnCode);
152	
153	            if ($returnCode !== 0) {
154	                throw new \RuntimeException(
155	                    'mysqldump exited with code ' . $returnCode . ': ' . implode(' ', $output)
156	                );
157	            }
158	        } finally {
159	            @unlink($optFile);
160	        }
161	
162	        return $dumpPath;
163	    }
164	
165	    // -------------------------------------------------------------------------
166	    // Manifest building
167	    // -------------------------------------------------------------------------
168	
169	    /**
170	     * Build the backup manifest.
171	     *
172	     * The manifest records:
173	     *   - dump_file: relative storage path to the .sql.gz artifact
174	     *   - dump_size_bytes: compressed dump file size in bytes
175	     *   - tables: array of {name, row_count} for all application tables
176	     *   - attachment_file_count: number of attachment files in storage
177	     *   - attachment_storage_bytes: total byte count in attachment storage
178	     *   - created_at: ISO-8601 timestamp of manifest creation
179	     *
180	     * @param string $dumpPath Absolute path to the .sql.gz file
181	     */
182	    private function buildManifest(string $dumpPath): array
183	    {
184	        $dumpSizeBytes = file_exists($dumpPath) ? filesize($dumpPath) : 0;
185	
186	        // Store only the filename (relative to the backups/ directory) in the manifest
187	        $dumpFilename = basename($dumpPath);
188	
189	        return [
190	            'created_at'               => now()->toIso8601String(),
191	            'dump_file'                => 'backups/' . $dumpFilename,
192	            'dump_size_bytes'          => $dumpSizeBytes,
193	            'tables'                   => $this->collectTableStats(),
194	            'attachment_file_count'    => $this->countAttachmentFiles(),
195	            'attachment_storage_bytes' => $this->sumAttachmentStorageBytes(),
196	        ];
197	    }
198	
199	    /**
200	     * Collect row counts for all application tables.
201	     */
202	    private function collectTableStats(): array
203	    {
204	        $tables = [
205	            'users', 'roles', 'departments', 'documents', 'document_versions',
206	            'attachments', 'attachment_links', 'audit_events', 'idempotency_keys',
207	            'configuration_sets', 'configuration_versions', 'canary_rollout_targets',
208	            'configuration_rules', 'workflow_templates', 'workflow_template_nodes',
209	            'workflow_instances', 'workflow_nodes', 'approvals', 'to_do_items',
210	            'document_number_sequences', 'sales_documents', 'sales_line_items',
211	            'returns', 'inventory_movements', 'backup_jobs', 'metrics_snapshots',
212	            'structured_logs', 'failed_login_attempts',
213	        ];
214	
215	        $stats = [];
216	        foreach ($tables as $table) {
217	            try {
218	                $count = DB::table($table)->count();
219	                $stats[] = ['table' => $table, 'row_count' => $count];
220	            } catch (\Throwable) {
221	                $stats[] = ['table' => $table, 'row_count' => null, 'error' => 'inaccessible'];
222	            }
223	        }
224	
225	        return $stats;
226	    }
227	
228	    /**
229	     * Count encrypted attachment files in local storage.
230	     */
231	    private function countAttachmentFiles(): int
232	    {
233	        try {
234	            $files = Storage::disk('local')->allFiles('attachments');
235	            return count($files);
236	        } catch (\Throwable) {
237	            return 0;
238	        }
239	    }
240	
241	    /**
242	     * Sum total bytes of attachment files in local storage.
243	     */
244	    private function sumAttachmentStorageBytes(): int
245	    {
246	        try {
247	            $files = Storage::disk('local')->allFiles('attachments');
248	            $total = 0;
249	            foreach ($files as $file) {
250	                $total += Storage::disk('local')->size($file);
251	            }
252	            return $total;
253	        } catch (\Throwable) {
254	            return 0;
255	        }
256	    }
257	
258	    /**
259	     * Compute total backup size in bytes: dump artifact + attachment files.
260	     */
261	    private function estimateSizeBytes(array $manifest): int
262	    {
263	        return (int) ($manifest['dump_size_bytes'] ?? 0)
264	             + (int) ($manifest['attachment_storage_bytes'] ?? 0);
265	    }
266	}
