3	namespace App\Infrastructure\Security;
4	
5	use RuntimeException;
6	
7	/**
8	 * AES-256-CBC encryption service for attachment payloads.
9	 *
10	 * Key source: ATTACHMENT_ENCRYPTION_KEY env var (base64-encoded 32 bytes).
11	 * This service intentionally does NOT use Laravel's APP_KEY or Crypt facade —
12	 * attachment encryption must remain independent of the application key so that
13	 * key rotation can be managed separately.
14	 */
15	class EncryptionService
16	{
17	    private const CIPHER = 'AES-256-CBC';
18	    private const IV_LENGTH = 16;
19	
20	    /**
21	     * Key registry for rotation support.
22	     * Format: ['v1' => <raw 32-byte string>, ...]
23	     */
24	    private array $keys;
25	
26	    public function __construct()
27	    {
28	        $encoded = config('meridian.attachments.encryption_key');
29	
30	        if (empty($encoded)) {
31	            throw new RuntimeException(
32	                'ATTACHMENT_ENCRYPTION_KEY is not configured. ' .
33	                'Generate one with: php -r "echo base64_encode(random_bytes(32));"'
34	            );
35	        }
36	
37	        $rawKey = base64_decode($encoded, strict: true);
38	
39	        if ($rawKey === false || strlen($rawKey) !== 32) {
40	            throw new RuntimeException(
41	                'ATTACHMENT_ENCRYPTION_KEY must be a base64-encoded 32-byte string.'
42	            );
43	        }
44	
45	        $this->keys = ['v1' => $rawKey];
46	    }
47	
48	    /**
49	     * Encrypt plaintext using AES-256-CBC with a random IV.
50	     *
51	     * @return array{ciphertext: string, iv: string, key_id: string}
52	     *              All values are base64-encoded strings safe for storage.
53	     */
54	    public function encrypt(string $plaintext): array
55	    {
56	        $iv         = random_bytes(self::IV_LENGTH);
57	        $key        = $this->resolveKey('v1');
58	        $encrypted  = openssl_encrypt($plaintext, self::CIPHER, $key, OPENSSL_RAW_DATA, $iv);
59	
60	        if ($encrypted === false) {
61	            throw new RuntimeException('Encryption failed: ' . openssl_error_string());
62	        }
63	
64	        return [
65	            'ciphertext' => base64_encode($encrypted),
66	            'iv'         => base64_encode($iv),
67	            'key_id'     => 'v1',
68	        ];
69	    }
70	
71	    /**
72	     * Decrypt a ciphertext produced by encrypt().
73	     *
74	     * @param string $ciphertext Base64-encoded ciphertext
75	     * @param string $iv         Base64-encoded IV
76	     * @param string $keyId      Key identifier used during encryption
77	     */
78	    public function decrypt(string $ciphertext, string $iv, string $keyId): string
79	    {
80	        $key       = $this->resolveKey($keyId);
81	        $rawIv     = base64_decode($iv, strict: true);
82	        $rawCipher = base64_decode($ciphertext, strict: true);
83	
84	        if ($rawIv === false || $rawCipher === false) {
85	            throw new RuntimeException('Invalid base64 encoding in ciphertext or IV.');
86	        }
87	
88	        $decrypted = openssl_decrypt($rawCipher, self::CIPHER, $key, OPENSSL_RAW_DATA, $rawIv);
89	
90	        if ($decrypted === false) {
91	            throw new RuntimeException('Decryption failed: ' . openssl_error_string());
92	        }
93	
94	        return $decrypted;
95	    }
96	
97	    /**
98	     * The currently active key ID (used when encrypting new payloads).
99	     */
100	    public function getActiveKeyId(): string
101	    {
102	        return 'v1';
103	    }
104	
105	    /**
106	     * Resolve a raw encryption key by its ID.
107	     */
108	    private function resolveKey(string $keyId): string
109	    {
110	        if (!isset($this->keys[$keyId])) {
111	            throw new RuntimeException("Unknown encryption key ID: {$keyId}");
112	        }
113	
114	        return $this->keys[$keyId];
115	    }
116	}
