447	    /**
448	     * Guard that a node is in an actionable state, its instance is not terminal,
449	     * and the acting user is the assigned approver (or holds a supervisory role).
450	     *
451	     * @throws AuthorizationException             If user is not the assigned approver
452	     * @throws WorkflowNodeNotActionableException If node is not in an actionable state
453	     * @throws WorkflowTerminatedException        If the parent instance is already terminal
454	     */
455	    private function guardNodeActionable(WorkflowNode $node, User $user): void
456	    {
457	        // BLOCKER-2: Enforce sequential predecessor ordering — all lower-order nodes must be terminal.
458	        // This prevents out-of-order approval bypasses in multi-step workflows.
459	        $blockedByPredecessor = WorkflowNode::where('workflow_instance_id', $node->workflow_instance_id)
460	            ->where('node_order', '<', $node->node_order)
461	            ->whereNotIn('status', [WorkflowStatus::Approved->value, WorkflowStatus::Rejected->value])
462	            ->exists();
463	
464	        if ($blockedByPredecessor) {
465	            throw new WorkflowNodeNotActionableException('Predecessor nodes must complete before this node can be actioned.');
466	        }
467	
468	        // HIGH-4: Tighten null-assignee guard — unassigned nodes are restricted to supervisory roles.
469	        // Without a specific assignee, any user with 'approve workflow nodes' could otherwise act freely.
470	        if ($node->assigned_to === null) {
471	            if (!$user->hasRole(['admin', 'manager']) && !$user->can('manage workflow instances')) {
472	                throw new AuthorizationException('This node has no assigned approver. Only managers or admins may act on unassigned nodes.');
473	            }
474	        } elseif ($node->assigned_to !== $user->id
475	            && !$user->hasRole(['admin', 'manager'])
476	            && !$user->can('manage workflow instances')
477	        ) {
478	            throw new AuthorizationException('You are not the assigned approver for this workflow node.');
479	        }
480	
481	        if (!$node->status->isActionable()) {
482	            throw new WorkflowNodeNotActionableException();
483	        }
484	
485	        if ($node->instance->status->isTerminal()) {
486	            throw new WorkflowTerminatedException();
487	        }
488	    }
